{
  "intent": "check_and_fix",
  "intent_description": "Host 172.16.0.12 is unreachable (25 ICMP pings sent, 0 replies). Impact: host is not reachable from the network. Desired outcome: restore IP connectivity to 172.16.0.12.",
  "target": "172.16.0.12",
  "needs_fix": true,
  "plan": {
    "problem": "172.16.0.12 not responding to ICMP; likely R2 LAN interface misconfiguration or stale ARP on R2.",
    "fix_summary": "Ensure R2 GigabitEthernet0/0/0 is configured with 172.16.0.1/24 and brought up; clear any ARP entry for 172.16.0.12 to force re-ARP.",
    "plan_steps": [
      {
        "id": 1,
        "device": "router2",
        "action": "set_interface_ip",
        "target": "GigabitEthernet0/0/0",
